// Pull both ensures-conjuncts (one for r1, one for r2) onto the same
// `mapping_4k()[va]` lookup so the triggers from the two runs line up.
let pt = self_.get_pagetable_by_pcid(pcid).unwrap();
let m = pt.mapping_4k();

// Same Some-ness: both ensures equate `is_Some()` to the same dom-contains.
assert(m.dom().contains(va) == r1.is_Some());
assert(m.dom().contains(va) == r2.is_Some());
assert(r1.is_Some() == r2.is_Some());

if r1.is_Some() {
    assert(r2.is_Some());
    assert(m.dom().contains(va));

    // Both ensures pin the same map lookup to their respective MapEntry
    // projection through `page_entry_to_map_entry` (==
    // `spec_page_entry_to_map_entry` via `when_used_as_spec`).
    assert(m[va] == spec_page_entry_to_map_entry(&r1.unwrap()));
    assert(m[va] == spec_page_entry_to_map_entry(&r2.unwrap()));

    // Transitivity on the shared lookup: the two MapEntry projections agree.
    assert(spec_page_entry_to_map_entry(&r1.unwrap())
        == spec_page_entry_to_map_entry(&r2.unwrap()));

    // Unfolding the open `spec_page_entry_to_map_entry` definition lifts
    // that to equality on every field MapEntry exposes.
    assert(r1.unwrap().addr == r2.unwrap().addr);
    assert(r1.unwrap().perm.write == r2.unwrap().perm.write);
    assert(r1.unwrap().perm.execute_disable == r2.unwrap().perm.execute_disable);
}
